"use strict";(globalThis.webpackChunklearncpp_docs=globalThis.webpackChunklearncpp_docs||[]).push([[640],{9913(r,n,e){e.r(n),e.d(n,{assets:()=>c,contentTitle:()=>o,default:()=>p,frontMatter:()=>s,metadata:()=>t,toc:()=>i});const t=JSON.parse('{"id":"cpp11/perfect-forwarding","title":"\u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding)","description":"C++11 \u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding) \u6559\u5b66\u793a\u4f8b","source":"@site/docs/cpp11/12-perfect-forwarding.md","sourceDirName":"cpp11","slug":"/cpp11/12-perfect-forwarding","permalink":"/LearnModernCpp/docs/cpp11/12-perfect-forwarding","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"cpp11","permalink":"/LearnModernCpp/docs/tags/cpp-11"},{"inline":true,"label":"perfect_forwarding","permalink":"/LearnModernCpp/docs/tags/perfect-forwarding"}],"version":"current","sidebarPosition":13,"frontMatter":{"sidebar_position":13,"slug":"12-perfect-forwarding","title":"\u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding)","description":"C++11 \u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding) \u6559\u5b66\u793a\u4f8b","tags":["cpp11","perfect_forwarding"]},"sidebar":"docs","previous":{"title":"\u79fb\u52a8\u8bed\u4e49 (Move Semantics)","permalink":"/LearnModernCpp/docs/cpp11/11-move-semantics"},"next":{"title":"noexcept \u8bf4\u660e\u7b26\u4e0e\u8fd0\u7b97\u7b26","permalink":"/LearnModernCpp/docs/cpp11/13-noexcept"}}');var d=e(74848),a=e(28453);const s={sidebar_position:13,slug:"12-perfect-forwarding",title:"\u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding)",description:"C++11 \u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding) \u6559\u5b66\u793a\u4f8b",tags:["cpp11","perfect_forwarding"]},o="\u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding)",c={},i=[{value:"\u5b8c\u6574\u6e90\u7801",id:"\u5b8c\u6574\u6e90\u7801",level:2},{value:"\u53c2\u8003\u94fe\u63a5",id:"\u53c2\u8003\u94fe\u63a5",level:2}];function l(r){const n={a:"a",code:"code",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",pre:"pre",ul:"ul",...(0,a.R)(),...r.components};return(0,d.jsxs)(d.Fragment,{children:[(0,d.jsx)(n.header,{children:(0,d.jsx)(n.h1,{id:"\u5b8c\u7f8e\u8f6c\u53d1-perfect-forwarding",children:"\u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding)"})}),"\n",(0,d.jsx)(n.p,{children:"C++11 \u6807\u51c6\u5f15\u5165\u7684 \u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding) \u7279\u6027\u5b8c\u6574\u6559\u5b66\u793a\u4f8b\u3002"}),"\n",(0,d.jsx)(n.h2,{id:"\u5b8c\u6574\u6e90\u7801",children:"\u5b8c\u6574\u6e90\u7801"}),"\n",(0,d.jsx)(n.pre,{children:(0,d.jsx)(n.code,{className:"language-cpp",metastring:'title="cpp11/12_perfect_forwarding.cpp"',children:'/**\r\n * ============================================================\r\n * \u7279\u6027\u540d\u79f0: \u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding)\r\n * \u6240\u5c5e\u6807\u51c6: C++11\r\n * ============================================================\r\n *\r\n * [\u662f\u4ec0\u4e48]: \u901a\u8fc7\u4e07\u80fd\u5f15\u7528(T&&)\u548cstd::forward<T>()\uff0c\u5c06\u53c2\u6570\u7684\r\n *          \u503c\u7c7b\u522b\uff08\u5de6\u503c/\u53f3\u503c\uff09\u539f\u5c01\u4e0d\u52a8\u5730\u4f20\u9012\u7ed9\u4e0b\u4e00\u4e2a\u51fd\u6570\u3002\r\n *\r\n * [\u4e3a\u4ec0\u4e48\u5f15\u5165]: C++03\u4e2d\u7f16\u5199\u901a\u7528\u5305\u88c5\u51fd\u6570\uff08\u5982\u5de5\u5382\u51fd\u6570\u3001emplace\u7b49\uff09\r\n *   \u65f6\uff0c\u65e0\u6cd5\u540c\u65f6\u9ad8\u6548\u5904\u7406\u5de6\u503c\u548c\u53f3\u503c\u53c2\u6570\u3002\u8981\u4e48\u4e22\u5931\u53f3\u503c\u6027\u5bfc\u81f4\r\n *   \u591a\u4f59\u62f7\u8d1d\uff0c\u8981\u4e48\u9700\u89812^N\u4e2a\u91cd\u8f7d\u3002\u5b8c\u7f8e\u8f6c\u53d1\u4e00\u4e3e\u89e3\u51b3\u4e86\u8fd9\u4e2a\u95ee\u9898\u3002\r\n *\r\n * [\u5173\u952e\u8981\u70b9]:\r\n *   - \u4e07\u80fd\u5f15\u7528(Universal Reference): \u6a21\u677f\u53c2\u6570 T&& \u4e2dT\u662f\u63a8\u5bfc\u7684\r\n *   - \u5f15\u7528\u6298\u53e0\u89c4\u5219: T& + & = T&, T& + && = T&, T&& + & = T&, T&& + && = T&&\r\n *   - std::forward<T>(arg): \u6709\u6761\u4ef6\u5730\u8f6c\u6362\u2014\u2014\u5de6\u503c\u4fdd\u6301\u5de6\u503c\uff0c\u53f3\u503c\u4fdd\u6301\u53f3\u503c\r\n *   - std::move\u662f\u65e0\u6761\u4ef6\u8f6c\u6362\uff0cstd::forward\u662f\u6709\u6761\u4ef6\u8f6c\u6362\r\n * ============================================================\r\n */\r\n\r\n#include <iostream>\r\n#include <string>\r\n#include <vector>\r\n#include <memory>\r\n#include <utility>\r\n#include <type_traits>\r\n\r\n// ============================================================\r\n// \u8f85\u52a9\uff1a\u5c55\u793a\u5de6\u503c/\u53f3\u503c\u4fe1\u606f\r\n// ============================================================\r\nclass Heavy {\r\npublic:\r\n    Heavy() : name_("\u9ed8\u8ba4") {\r\n        std::cout << "    Heavy() \u9ed8\u8ba4\u6784\u9020" << std::endl;\r\n    }\r\n    Heavy(const std::string& n) : name_(n) {\r\n        std::cout << "    Heavy(const&) \u62f7\u8d1d\u6784\u9020: " << name_ << std::endl;\r\n    }\r\n    Heavy(std::string&& n) : name_(std::move(n)) {\r\n        std::cout << "    Heavy(&&) \u79fb\u52a8\u6784\u9020: " << name_ << std::endl;\r\n    }\r\n    Heavy(const Heavy& other) : name_(other.name_) {\r\n        std::cout << "    Heavy \u62f7\u8d1d: " << name_ << std::endl;\r\n    }\r\n    Heavy(Heavy&& other) noexcept : name_(std::move(other.name_)) {\r\n        std::cout << "    Heavy \u79fb\u52a8: " << name_ << std::endl;\r\n    }\r\n    const std::string& name() const { return name_; }\r\nprivate:\r\n    std::string name_;\r\n};\r\n\r\n// \u76ee\u6807\u51fd\u6570\uff1a\u533a\u5206\u5de6\u503c\u548c\u53f3\u503c\r\nvoid target(const Heavy& h) {\r\n    std::cout << "  -> target(const Heavy&) \u5de6\u503c\u7248\u672c: " << h.name() << std::endl;\r\n}\r\n\r\nvoid target(Heavy&& h) {\r\n    std::cout << "  -> target(Heavy&&) \u53f3\u503c\u7248\u672c: " << h.name() << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u57fa\u7840\u7528\u6cd5\r\n// ============================================================\r\n\r\n// \u4e0d\u5b8c\u7f8e\u8f6c\u53d1\u7684\u95ee\u9898\r\nvoid bad_wrapper(const Heavy& h) {\r\n    std::cout << "  bad_wrapper(const&) -> ";\r\n    target(h); // \u603b\u662f\u8c03\u7528\u5de6\u503c\u7248\u672c!\r\n}\r\n\r\nvoid bad_wrapper(Heavy&& h) {\r\n    std::cout << "  bad_wrapper(&&) -> ";\r\n    target(h); // \u8fd8\u662f\u8c03\u7528\u5de6\u503c\u7248\u672c! \u56e0\u4e3ah\u6709\u540d\u5b57\uff0c\u662f\u5de6\u503c!\r\n}\r\n\r\n// \u5b8c\u7f8e\u8f6c\u53d1\r\ntemplate <typename T>\r\nvoid good_wrapper(T&& arg) {  // T&& \u5728\u8fd9\u91cc\u662f\u4e07\u80fd\u5f15\u7528\r\n    std::cout << "  good_wrapper -> ";\r\n    target(std::forward<T>(arg)); // \u4fdd\u6301\u503c\u7c7b\u522b\r\n}\r\n\r\nvoid basic_usage() {\r\n    std::cout << "===== \u57fa\u7840\u7528\u6cd5 =====" << std::endl;\r\n\r\n    Heavy obj("\u5bf9\u8c61A");\r\n\r\n    // 1. \u4e0d\u5b8c\u7f8e\u8f6c\u53d1\u7684\u95ee\u9898\r\n    std::cout << "\\n--- \u4e0d\u5b8c\u7f8e\u8f6c\u53d1 ---" << std::endl;\r\n    std::cout << "\u4f20\u5de6\u503c:" << std::endl;\r\n    bad_wrapper(obj);                // \u5de6\u503c -> const& -> \u8c03\u7528\u5de6\u503c\u7248\u672c OK\r\n    std::cout << "\u4f20\u53f3\u503c:" << std::endl;\r\n    bad_wrapper(Heavy("\u4e34\u65f6\u5bf9\u8c61"));   // \u53f3\u503c -> && -> \u4f46\u4ecd\u8c03\u7528\u5de6\u503c\u7248\u672c! \u9519!\r\n\r\n    // 2. \u5b8c\u7f8e\u8f6c\u53d1\r\n    std::cout << "\\n--- \u5b8c\u7f8e\u8f6c\u53d1 ---" << std::endl;\r\n    std::cout << "\u4f20\u5de6\u503c:" << std::endl;\r\n    good_wrapper(obj);               // T\u63a8\u5bfc\u4e3aHeavy&, forward\u4fdd\u6301\u5de6\u503c\r\n    std::cout << "\u4f20\u53f3\u503c:" << std::endl;\r\n    good_wrapper(Heavy("\u4e34\u65f6\u5bf9\u8c61"));  // T\u63a8\u5bfc\u4e3aHeavy, forward\u8f6c\u4e3a\u53f3\u503c\r\n\r\n    // 3. \u5f15\u7528\u6298\u53e0\u89c4\u5219\u8bf4\u660e\r\n    std::cout << "\\n--- \u5f15\u7528\u6298\u53e0\u89c4\u5219 ---" << std::endl;\r\n    std::cout << "\u4f20\u5de6\u503c\u65f6: T=Heavy&, T&&=Heavy& && = Heavy& (\u5de6\u503c\u5f15\u7528)" << std::endl;\r\n    std::cout << "\u4f20\u53f3\u503c\u65f6: T=Heavy,  T&&=Heavy&&            (\u53f3\u503c\u5f15\u7528)" << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u8fdb\u9636\u7528\u6cd5\r\n// ============================================================\r\n\r\n// 1. \u5de5\u5382\u51fd\u6570\u6a21\u5f0f \u2014\u2014 \u5b8c\u7f8e\u8f6c\u53d1\u7684\u7ecf\u5178\u5e94\u7528\r\ntemplate <typename T, typename... Args>\r\nstd::unique_ptr<T> make_unique_impl(Args&&... args) {\r\n    return std::unique_ptr<T>(new T(std::forward<Args>(args)...));\r\n}\r\n\r\nclass Product {\r\npublic:\r\n    Product(const std::string& name, int quantity, double price)\r\n        : name_(name), qty_(quantity), price_(price) {\r\n        std::cout << "  \u521b\u5efa\u4ea7\u54c1: " << name_ << " x" << qty_\r\n                  << " @" << price_ << std::endl;\r\n    }\r\n    void show() const {\r\n        std::cout << "  \u4ea7\u54c1: " << name_ << ", \u6570\u91cf=" << qty_\r\n                  << ", \u5355\u4ef7=" << price_ << std::endl;\r\n    }\r\nprivate:\r\n    std::string name_;\r\n    int qty_;\r\n    double price_;\r\n};\r\n\r\n// 2. \u901a\u7528\u7684\u65e5\u5fd7\u5305\u88c5\u5668\r\ntemplate <typename Func, typename... Args>\r\nauto log_call(const std::string& tag, Func&& func, Args&&... args)\r\n    -> decltype(func(std::forward<Args>(args)...)) {\r\n    std::cout << "[" << tag << "] \u8c03\u7528\u5f00\u59cb" << std::endl;\r\n    auto result = func(std::forward<Args>(args)...);\r\n    std::cout << "[" << tag << "] \u8c03\u7528\u7ed3\u675f, \u7ed3\u679c=" << result << std::endl;\r\n    return result;\r\n}\r\n\r\nint add(int a, int b) { return a + b; }\r\n\r\n// 3. emplace_back\u98ce\u683c\u7684\u63a5\u53e3\r\ntemplate <typename T>\r\nclass SimpleVector {\r\npublic:\r\n    template <typename... Args>\r\n    void emplace_back(Args&&... args) {\r\n        // \u76f4\u63a5\u5728\u5b58\u50a8\u4f4d\u7f6e\u6784\u9020\u5bf9\u8c61\uff0c\u907f\u514d\u989d\u5916\u7684\u62f7\u8d1d/\u79fb\u52a8\r\n        data_.emplace_back(std::forward<Args>(args)...);\r\n        std::cout << "  emplace_back\u5b8c\u6210, \u5927\u5c0f=" << data_.size() << std::endl;\r\n    }\r\n\r\n    void show() const {\r\n        for (const auto& item : data_) {\r\n            std::cout << "  -> " << item.name() << std::endl;\r\n        }\r\n    }\r\n\r\nprivate:\r\n    std::vector<T> data_;\r\n};\r\n\r\nvoid advanced_usage() {\r\n    std::cout << "\\n===== \u8fdb\u9636\u7528\u6cd5 =====" << std::endl;\r\n\r\n    // 1. \u5de5\u5382\u51fd\u6570\r\n    std::cout << "--- \u5de5\u5382\u51fd\u6570 ---" << std::endl;\r\n    auto product = make_unique_impl<Product>("\u7b14\u8bb0\u672c\u7535\u8111", 5, 6999.0);\r\n    product->show();\r\n\r\n    // 2. \u65e5\u5fd7\u5305\u88c5\u5668\r\n    std::cout << "\\n--- \u65e5\u5fd7\u5305\u88c5\u5668 ---" << std::endl;\r\n    log_call("\u52a0\u6cd5", add, 3, 5);\r\n\r\n    // 3. emplace\u98ce\u683c\r\n    std::cout << "\\n--- emplace\u98ce\u683c ---" << std::endl;\r\n    SimpleVector<Heavy> sv;\r\n    std::string name = "\u5bf9\u8c61X";\r\n    std::cout << "\u7528\u5de6\u503cemplace:" << std::endl;\r\n    sv.emplace_back(name);      // \u5b8c\u7f8e\u8f6c\u53d1\u5de6\u503c -> \u62f7\u8d1d\u6784\u9020\r\n    std::cout << "\u7528\u53f3\u503cemplace:" << std::endl;\r\n    sv.emplace_back(std::string("\u5bf9\u8c61Y")); // \u5b8c\u7f8e\u8f6c\u53d1\u53f3\u503c -> \u79fb\u52a8\u6784\u9020\r\n    sv.show();\r\n}\r\n\r\n// ============================================================\r\n// \u6613\u9519\u70b9\u4e0e\u9677\u9631\r\n// ============================================================\r\n\r\n// \u9677\u96311: \u4e0d\u662f\u6240\u6709T&&\u90fd\u662f\u4e07\u80fd\u5f15\u7528\r\nclass Specific {\r\npublic:\r\n    // \u8fd9\u4e0d\u662f\u4e07\u80fd\u5f15\u7528! \u56e0\u4e3aT\u4e0d\u662f\u5728\u6b64\u5904\u63a8\u5bfc\u7684\r\n    // \u5b83\u5c31\u662f\u4e00\u4e2a\u666e\u901a\u7684\u53f3\u503c\u5f15\u7528\r\n    void process(std::string&& s) {\r\n        std::cout << "  Specific::process(string&&): " << s << std::endl;\r\n    }\r\n};\r\n\r\n// \u9677\u96312: auto&&\u662f\u4e07\u80fd\u5f15\u7528\r\nvoid demo_auto_universal_ref() {\r\n    Heavy obj("auto\u6d4b\u8bd5");\r\n    auto&& ref1 = obj;          // ref1\u662fHeavy& (\u5de6\u503c\u7ed1\u5b9a)\r\n    auto&& ref2 = Heavy("\u4e34\u65f6"); // ref2\u662fHeavy&& (\u53f3\u503c\u7ed1\u5b9a)\r\n    std::cout << "  auto&&\u7ed1\u5b9a\u5de6\u503c: " << ref1.name() << std::endl;\r\n    std::cout << "  auto&&\u7ed1\u5b9a\u53f3\u503c: " << ref2.name() << std::endl;\r\n}\r\n\r\n// \u9677\u96313: forward\u53ea\u7528\u4e00\u6b21\r\ntemplate <typename T>\r\nvoid multiple_forward_bad(T&& arg) {\r\n    // target(std::forward<T>(arg)); // \u7b2c\u4e00\u6b21forward\r\n    // target(std::forward<T>(arg)); // \u7b2c\u4e8c\u6b21forward: \u5982\u679carg\u662f\u53f3\u503c\uff0c\u7b2c\u4e00\u6b21\u53ef\u80fd\u5df2\u79fb\u8d70!\r\n    // \u6b63\u786e\u505a\u6cd5: \u53eaforward\u4e00\u6b21\uff0c\u6216\u8005\u5728\u6700\u540e\u4e00\u6b21\u4f7f\u7528\u65f6\u624dforward\r\n    target(arg);                      // \u7b2c\u4e00\u6b21: \u5f53\u4f5c\u5de6\u503c\u4f7f\u7528\r\n    target(std::forward<T>(arg));     // \u6700\u540e\u4e00\u6b21: forward\r\n}\r\n\r\nvoid pitfalls() {\r\n    std::cout << "\\n===== \u6613\u9519\u70b9\u4e0e\u9677\u9631 =====" << std::endl;\r\n\r\n    // \u9677\u96311: \u533a\u5206\u4e07\u80fd\u5f15\u7528\u548c\u53f3\u503c\u5f15\u7528\r\n    std::cout << "\u9677\u96311: \u4e07\u80fd\u5f15\u7528 vs \u53f3\u503c\u5f15\u7528" << std::endl;\r\n    std::cout << "  template<typename T> void f(T&& x) -> \u4e07\u80fd\u5f15\u7528(T\u662f\u63a8\u5bfc\u7684)" << std::endl;\r\n    std::cout << "  void f(string&& x)                  -> \u53f3\u503c\u5f15\u7528(\u7c7b\u578b\u786e\u5b9a)" << std::endl;\r\n    std::cout << "  auto&& x = expr                     -> \u4e07\u80fd\u5f15\u7528" << std::endl;\r\n\r\n    // \u9677\u96312: auto&&\r\n    std::cout << "\\n\u9677\u96312: auto&&\u4e5f\u662f\u4e07\u80fd\u5f15\u7528" << std::endl;\r\n    demo_auto_universal_ref();\r\n\r\n    // \u9677\u96313: \u4e0d\u8981\u591a\u6b21forward\u540c\u4e00\u53c2\u6570\r\n    std::cout << "\\n\u9677\u96313: \u4e0d\u8981\u591a\u6b21forward\u540c\u4e00\u4e2a\u53c2\u6570" << std::endl;\r\n    std::cout << "  forward\u540e\u53c2\u6570\u53ef\u80fd\u5df2\u88ab\u79fb\u8d70\uff0c\u518d\u6b21\u4f7f\u7528\u662f\u672a\u5b9a\u4e49\u884c\u4e3a" << std::endl;\r\n    Heavy h("\u6d4b\u8bd5");\r\n    multiple_forward_bad(std::move(h));\r\n\r\n    // \u9677\u96314: std::move vs std::forward\r\n    std::cout << "\\n\u9677\u96314: std::move vs std::forward" << std::endl;\r\n    std::cout << "  std::move: \u65e0\u6761\u4ef6\u8f6c\u4e3a\u53f3\u503c\u5f15\u7528" << std::endl;\r\n    std::cout << "  std::forward: \u6709\u6761\u4ef6\u8f6c\u53d1\uff08\u4fdd\u6301\u539f\u59cb\u503c\u7c7b\u522b\uff09" << std::endl;\r\n    std::cout << "  \u7528\u5728\u786e\u5b9a\u8981\u79fb\u52a8\u7684\u5730\u65b9: std::move" << std::endl;\r\n    std::cout << "  \u7528\u5728\u6a21\u677f\u8f6c\u53d1\u7684\u5730\u65b9: std::forward" << std::endl;\r\n\r\n    // \u6700\u4f73\u5b9e\u8df5\r\n    std::cout << "\\n\u6700\u4f73\u5b9e\u8df5:" << std::endl;\r\n    std::cout << "  1. \u4e07\u80fd\u5f15\u7528\u53c2\u6570\u53ea\u914d\u5408std::forward\u4f7f\u7528" << std::endl;\r\n    std::cout << "  2. \u786e\u5b9a\u8981\u79fb\u52a8\u65f6\u4f7f\u7528std::move" << std::endl;\r\n    std::cout << "  3. \u6bcf\u4e2a\u53c2\u6570\u6700\u591aforward/move\u4e00\u6b21" << std::endl;\r\n    std::cout << "  4. \u5b8c\u7f8e\u8f6c\u53d1\u662f\u7f16\u5199\u901a\u7528\u5e93\u4ee3\u7801\u7684\u6838\u5fc3\u6280\u672f" << std::endl;\r\n}\r\n\r\n// ============================================================\r\n// \u4e3b\u51fd\u6570\r\n// ============================================================\r\nint main() {\r\n    std::cout << "========================================" << std::endl;\r\n    std::cout << "  C++11 \u7279\u6027: \u5b8c\u7f8e\u8f6c\u53d1" << std::endl;\r\n    std::cout << "========================================" << std::endl;\r\n\r\n    basic_usage();\r\n    advanced_usage();\r\n    pitfalls();\r\n\r\n    return 0;\r\n}\n'})}),"\n",(0,d.jsx)(n.h2,{id:"\u53c2\u8003\u94fe\u63a5",children:"\u53c2\u8003\u94fe\u63a5"}),"\n",(0,d.jsxs)(n.ul,{children:["\n",(0,d.jsx)(n.li,{children:(0,d.jsx)(n.a,{href:"https://en.cppreference.com/w/cpp/utility/forward",children:"cppreference: \u5b8c\u7f8e\u8f6c\u53d1 (Perfect Forwarding)"})}),"\n"]})]})}function p(r={}){const{wrapper:n}={...(0,a.R)(),...r.components};return n?(0,d.jsx)(n,{...r,children:(0,d.jsx)(l,{...r})}):l(r)}},28453(r,n,e){e.d(n,{R:()=>s,x:()=>o});var t=e(96540);const d={},a=t.createContext(d);function s(r){const n=t.useContext(a);return t.useMemo(function(){return"function"==typeof r?r(n):{...n,...r}},[n,r])}function o(r){let n;return n=r.disableParentContext?"function"==typeof r.components?r.components(d):r.components||d:s(r.components),t.createElement(a.Provider,{value:n},r.children)}}}]);